mapper.select:
select

from PARTY_ORGANIZATION t1
where t1.ID = #{id}

select

from PARTY_ORGANIZATION t1
where t1.party_code = #{partyCode}

select

from PARTY_ORGANIZATION t1

	
		and t1.PARTY_NAME like concat(concat('%',#{partyName}),'%')
	
	
		and t1.org_identity = #{orgIdentity}
	
	
		and t1.ATTRIBUTE_01 = #{attribute01}
	

order by t1.tree_sorts asc

select count(*) as party_count from party_member where
attribute_01 = #{id}
party_id in ( select id from party_organization t start with t.id = #{id} connect by prior t.id = t.parent_id)

select party_name
from
party_organization t where t.id != #{id}
start with t.id = #{id}
connect by prior t.id = t.parent_id

select count(*) as avc_count from PARTY_ACTIVIST where

	attribute_08 = #{id}


	PARTY_ID in (
	select id from party_organization t start
	with t.id =#{id} connect by prior t.id = t.parent_id
	)
